samples.hooks:
// PostToolUse · 业务 tool 全量审计
// matcher: paper.* | live.* | factor.* | research.*
export const auditLog: HookHandler = async (ctx) => {
  await jsonl.append(`audit/${today()}.jsonl`, {
    ts:        nowIso(),
    tool:      ctx.toolName,
    sessionId: ctx.sessionId,
    isError:   ctx.isError,
    input:     redact(ctx.toolInput),   // apiKey / approvalToken
    output:    redact(ctx.toolOutput),  // wallet / ssn / cvv → [REDACTED]
  });
  // blocking: false —— 审计是副作用，绝不卡业务路径
};

